#include<bits/stdc++.h>
using namespace std;
string s1,s2;
int tong[100101];
int main()
{
	int n;
	cin>>n;
	cin>>s1>>s2;
	for(int i=0;i<n;i++){
		if(s1[i]==s2[i])
		tong[i]++;
	}
	int cnt=0;
	for(int i=0;i<n-1;i++){
		if(!tong[i]&&tong[i+1]){
			cnt++;
		}
	}
	cout<<cnt;
}
